import asyncio
import websockets
import json

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = {}

    def add_item(self, item, quantity):
        if item in self.inventory:
            self.inventory[item] += quantity
        else:
            self.inventory[item] = quantity

    def remove_item(self, item, quantity):
        if item in self.inventory and self.inventory[item] >= quantity:
            self.inventory[item] -= quantity
            if self.inventory[item] == 0:
                del self.inventory[item]
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}

    async def register(self, websocket):
        username = await websocket.recv()
        self.players[username] = Player(username)
        await self.send_inventory(username)

    async def unregister(self, username):
        del self.players[username]

    async def send_inventory(self, username):
        player = self.players[username]
        await self.players[username].websocket.send(json.dumps({"inventory": player.inventory}))

    async def handle_trade(self, sender, receiver, item, quantity):
        if sender.remove_item(item, quantity):
            self.players[receiver].add_item(item, quantity)
            await self.send_inventory(sender.username)
            await self.send_inventory(receiver)
            return True
        return False

    async def handler(self, websocket, path):
        await self.register(websocket)
        try:
            async for message in websocket:
                data = json.loads(message)
                action = data.get("action")

                if action == "trade":
                    receiver = data["receiver"]
                    item = data["item"]
                    quantity = data["quantity"]
                    if receiver in self.players:
                        success = await self.handle_trade(self.players[websocket.username], self.players[receiver], item, quantity)
                        if not success:
                            await websocket.send(json.dumps({"error": "Trade failed"}))
                    else:
                        await websocket.send(json.dumps({"error": "Receiver not found"}))
        finally:
            await self.unregister(websocket.username)

    async def main(self):
        async with websockets.serve(self.handler, "localhost", 6789):
            await asyncio.Future()  # run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.main())